const firebaseConsoleMenus = [
  { section: 'アナリティクス', name: 'Dashboard', forMarketer: true },
  { section: 'アナリティクス', name: 'Events', forMarketer: true },
  { section: 'アナリティクス', name: 'Retention', forMarketer: true },
  { section: 'アナリティクス', name: 'Funnels', forMarketer: true },
  { section: 'エンゲージメント', name: 'Cloud Messaging', forMarketer: true },
  { section: 'エンゲージメント', name: 'A/B Testing', forMarketer: true },
  { section: 'エンゲージメント', name: 'Remote Config', forMarketer: false },
  { section: 'リリースとモニタリング', name: 'Crashlytics', forMarketer: true },
  { section: '構築', name: 'Authentication', forMarketer: false },
  { section: '構築', name: 'Firestore', forMarketer: false }
];

function getMarketerMenus(menus) {
  return menus.filter(menu => menu.forMarketer);
}

function groupBySection(menus) {
  return menus.reduce((groups, menu) => {
    if (!groups[menu.section]) groups[menu.section] = [];
    groups[menu.section].push(menu.name);
    return groups;
  }, {});
}

const marketerMenus = getMarketerMenus(firebaseConsoleMenus);
console.log('マーケター向けメニュー数:', marketerMenus.length);

const grouped = groupBySection(marketerMenus);
Object.entries(grouped).forEach(([section, names]) => {
  console.log(`\n[${section}]`);
  names.forEach(name => console.log(`  - ${name}`));
});
